arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    if eProg=0
    {
      if x>=oPlayer1.x {image_xscale=-1}
      else {image_xscale=1}
      y-=3
      
      moveMin+=1
      if moveMin>=7 {if y<=oPlayer1.y-26 {eProg=1}}
    }
    else if eProg>=1 and eProg<=15
    {
      eProg+=1
      if x>=oPlayer1.x {image_xscale=-1}
      else {image_xscale=1}
    }
    else if eProg>=16 {x+=5*image_xscale}
  }
  enemyStepEvent()
}
